class InvestigationService:
    """Service for managing investigations"""

    # Case Operations
    @staticmethod
    async def create_case(case_data: InvestigationCaseCreate) -> InvestigationCase:
        """Create new investigation case"""
        try:
            result = supabase.table("investigation_cases").insert(case_data.model_dump()).execute()
            return InvestigationCase(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to create case: {e}")
            raise

    @staticmethod
    async def get_case(case_id: str) -> Optional[InvestigationCase]:
        """Get case by ID"""
        try:
            result = supabase.table("investigation_cases").select("*").eq("case_id", case_id).execute()
            if result.data:
                return InvestigationCase(**result.data[0])
            return None
        except Exception as e:
            logger.error(f"Failed to get case: {e}")
            raise

    @staticmethod
    async def list_cases(
        status: Optional[str] = None,
        limit: int = 100,
        offset: int = 0
    ) -> List[InvestigationCase]:
        """List all cases with optional filtering"""
        try:
            query = supabase.table("investigation_cases").select("*")

            if status:
                query = query.eq("status", status)

            query = query.limit(limit).offset(offset)
            result = query.execute()

            return [InvestigationCase(**case) for case in result.data]
        except Exception as e:
            logger.error(f"Failed to list cases: {e}")
            raise

    @staticmethod
    async def update_case(case_id: str, update_data: InvestigationCaseUpdate) -> InvestigationCase:
        """Update case details"""
        try:
            data = {k: v for k, v in update_data.model_dump().items() if v is not None}
            data["updated_at"] = datetime.utcnow().isoformat()

            result = supabase.table("investigation_cases").update(data).eq("case_id", case_id).execute()
            return InvestigationCase(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to update case: {e}")
            raise

    @staticmethod
    async def delete_case(case_id: str) -> bool:
        """Delete case and all related data"""
        try:
            # Delete related data first
            supabase.table("investigation_wallets").delete().eq("case_id", case_id).execute()
            supabase.table("investigation_evidence").delete().eq("case_id", case_id).execute()
            supabase.table("investigation_entities").delete().eq("case_id", case_id).execute()
            supabase.table("investigation_timeline").delete().eq("case_id", case_id).execute()

            # Delete case
            supabase.table("investigation_cases").delete().eq("case_id", case_id).execute()
            return True
        except Exception as e:
            logger.error(f"Failed to delete case: {e}")
            raise

    # Entity Operations
    @staticmethod
    async def add_entity(entity_data: EntityCreate) -> Entity:
        """Add entity to case"""
        try:
            result = supabase.table("investigation_entities").insert(entity_data.model_dump()).execute()
            return Entity(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to add entity: {e}")
            raise

    @staticmethod
    async def get_case_entities(
        case_id: str,
        entity_type: Optional[str] = None,
        risk_level: Optional[str] = None
    ) -> List[Entity]:
