            if entity_type:
                query = query.eq("entity_type", entity_type)
            if risk_level:
                query = query.eq("risk_level", risk_level)

            result = query.execute()
            return [Entity(**entity) for entity in result.data]
        except Exception as e:
            logger.error(f"Failed to get entities: {e}")
            raise

    # Wallet Operations
    @staticmethod
    async def add_wallet(wallet_data: WalletCreate) -> Wallet:
        """Add wallet to case"""
        try:
            result = supabase.table("investigation_wallets").insert(wallet_data.model_dump()).execute()
            return Wallet(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to add wallet: {e}")
            raise

    @staticmethod
    async def get_case_wallets(
        case_id: str,
        chain: Optional[str] = None
    ) -> List[Wallet]:
        """Get all wallets for a case"""
        try:
            query = supabase.table("investigation_wallets").select("*").eq("case_id", case_id)

            if chain:
                query = query.eq("chain", chain)

            result = query.execute()
            return [Wallet(**wallet) for wallet in result.data]
        except Exception as e:
            logger.error(f"Failed to get wallets: {e}")
            raise

    @staticmethod
    async def get_wallet_by_address(case_id: str, address: str) -> Optional[Wallet]:
        """Get wallet by address"""
        try:
            result = supabase.table("investigation_wallets").select("*").eq("case_id", case_id).eq("address", address).execute()
            if result.data:
                return Wallet(**result.data[0])
            return None
        except Exception as e:
            logger.error(f"Failed to get wallet: {e}")
            raise

    # Evidence Operations
    @staticmethod
    async def add_evidence(evidence_data: EvidenceCreate) -> Evidence:
        """Add evidence to case"""
        try:
            result = supabase.table("investigation_evidence").insert(evidence_data.model_dump()).execute()
            return Evidence(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to add evidence: {e}")
            raise

    @staticmethod
    async def get_case_evidence(
        case_id: str,
        category: Optional[str] = None
    ) -> List[Evidence]:
        """Get all evidence for a case"""
        try:
            query = supabase.table("investigation_evidence").select("*").eq("case_id", case_id)

            if category:
                query = query.eq("category", category)

            result = query.execute()
            return [Evidence(**ev) for ev in result.data]
        except Exception as e:
            logger.error(f"Failed to get evidence: {e}")
            raise

    # Timeline Operations
    @staticmethod
    async def add_timeline_event(event_data: TimelineEventCreate) -> TimelineEvent:
        """Add timeline event"""
        try:
            result = supabase.table("investigation_timeline").insert(event_data.model_dump()).execute()
            return TimelineEvent(**result.data[0])
        except Exception as e:
            logger.error(f"Failed to add timeline event: {e}")
