    @staticmethod
    async def get_case_timeline(case_id: str) -> List[TimelineEvent]:
        """Get timeline for case"""
        try:
            result = supabase.table("investigation_timeline").select("*").eq("case_id", case_id).order("event_date").execute()
            return [TimelineEvent(**event) for event in result.data]
        except Exception as e:
            logger.error(f"Failed to get timeline: {e}")
            raise

    # Statistics
    @staticmethod
    async def get_case_stats(case_id: str) -> Dict[str, Any]:
        """Get statistics for a case"""
        try:
            wallets = supabase.table("investigation_wallets").select("count").eq("case_id", case_id).execute()
            evidence = supabase.table("investigation_evidence").select("count").eq("case_id", case_id).execute()
