"""
Wallet Analysis & Blockchain Service
"""
from web3 import Web3
from database.connection import supabase
from typing import List, Dict, Any, Optional
from config.settings import settings
import logging
import httpx

logger = logging.getLogger(__name__)

class WalletService:
    """Service for wallet analysis and blockchain operations"""

    def __init__(self):
        self.w3 = Web3(Web3.HTTPProvider(settings.ETHEREUM_RPC))
        self.bsc_w3 = Web3(Web3.HTTPProvider(settings.BSC_RPC))

    @staticmethod
    async def trace_wallet_transactions(
        address: str,
        chain: str = "ethereum",
        days: int = 90
    ) -> Dict[str, Any]:
        """Trace wallet transactions using external APIs"""
        try:
            # Use SolanaFM API for Solana, Etherscan/Blockscout for EVM
            if chain == "solana":
                return await WalletService._trace_solana_wallet(address, days)
            else:
                return await WalletService._trace_evm_wallet(address, chain, days)
        except Exception as e:
            logger.error(f"Failed to trace wallet {address}: {e}")
            return {"error": str(e), "address": address}

    @staticmethod
    async def _trace_evm_wallet(address: str, chain: str, days: int) -> Dict[str, Any]:
        """Trace EVM wallet (Ethereum, BSC, etc.)"""
        # For now, return structure - implement actual API calls later
        return {
            "address": address,
            "chain": chain,
            "balance": "0",
            "transaction_count": 0,
            "first_transaction": None,
            "last_transaction": None,
            "related_wallets": [],
            "high_value_transactions": [],
            "labels": []
        }

    @staticmethod
    async def _trace_solana_wallet(address: str, days: int) -> Dict[str, Any]:
        """Trace Solana wallet"""
        return {
            "address": address,
            "chain": "solana",
            "balance": "0",
            "transaction_count": 0,
            "first_transaction": None,
            "last_transaction": None,
            "related_wallets": [],
            "token_accounts": [],
            "labels": []
        }

    @staticmethod
    async def get_wallet_labels(address: str) -> List[str]:
        """Get labels for wallet from various sources"""
        labels = []

        # Check our database first
        try:
            result = supabase.table("investigation_entities").select("*").eq("entity_type", "wallet").execute()
            for entity in result.data:
                wallets = entity.get("wallets", {})
                if wallets.get("primary") == address.lower():
                    if entity.get("risk_level") == "high":
                        labels.append("high-risk")
                    if entity.get("metadata", {}).get("occurrences", 0) > 5:
                        labels.append("frequently-mentioned")
        except Exception as e:
            logger.warning(f"Failed to get labels from database: {e}")

        return labels

    @staticmethod
    async def calculate_risk_score(address: str, case_id: str) -> int:
        """Calculate risk score for wallet (0-100)"""
        score = 0

        try:
            # Get wallet data
            wallet_result = supabase.table("investigation_wallets").select("*").eq("case_id", case_id).eq("address", address).execute()

            if wallet_result.data:
                wallet = wallet_result.data[0]
                metadata = wallet.get("metadata", {})

                # Higher occurrence = higher risk
                occurrences = metadata.get("occurrences", 0)
                if occurrences > 10:
                    score += 30
                elif occurrences > 5:
                    score += 20
                elif occurrences > 1:
                    score += 10

                # Check entity risk level
                entity_result = supabase.table("investigation_entities").select("*").eq("case_id", case_id).eq("name", address).execute()
                if entity_result.data:
                    risk_level = entity_result.data[0].get("risk_level")
                    if risk_level == "high":
                        score += 40
                    elif risk_level == "medium":
                        score += 20

            return min(score, 100)
        except Exception as e:
            logger.error(f"Failed to calculate risk score: {e}")
            return 0

    @staticmethod
    async def find_wallet_clusters(case_id: str) -> List[Dict[str, Any]]:
        """Find clusters of related wallets"""
        try:
            # Get all wallets for case
            result = supabase.table("investigation_wallets").select("*").eq("case_id", case_id).execute()
            wallets = result.data

            # Simple clustering by source
            clusters = {}
            for wallet in wallets:
                source = wallet.get("source", "unknown")
                if source not in clusters:
                    clusters[source] = []
                clusters[source].append(wallet)

            return [
                {"source": source, "wallets": wallet_list, "count": len(wallet_list)}
                for source, wallet_list in clusters.items()
            ]
        except Exception as e:
            logger.error(f"Failed to find clusters: {e}")
            return []

    @staticmethod
    async def batch_trace_wallets(
        addresses: List[str],
        case_id: str,
        chain: str = "ethereum"
    ) -> List[Dict[str, Any]]:
        """Trace multiple wallets in batch"""
        results = []

        for address in addresses:
            try:
                trace_result = await WalletService.trace_wallet_transactions(address, chain)
                risk_score = await WalletService.calculate_risk_score(address, case_id)

                trace_result["risk_score"] = risk_score
                results.append(trace_result)

                # Update wallet with risk score
                supabase.table("investigation_wallets").update({
                    "risk_score": risk_score,
                    "metadata": {
                        **trace_result.get("metadata", {}),
                        "traced_at": "now",
                        "chain": chain
                    }
                }).eq("case_id", case_id).eq("address", address).execute()

            except Exception as e:
                logger.error(f"Failed to trace {address}: {e}")
                results.append({"address": address, "error": str(e)})

        return results

